import { useState, useEffect } from "react";
import { useQuery } from "@tanstack/react-query";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Badge } from "@/components/ui/badge";
import ResearchSubjects from "@/components/ResearchSubjects";
import BehavioralAnalysis from "@/components/BehavioralAnalysis";
import AudioRecorder from "@/components/AudioRecorder";
import StatCard from "@/components/StatCard";
import AccessibilityControls from "@/components/AccessibilityControls";
import HelpSystem from "@/components/HelpSystem";
import useKeyboardShortcuts from "@/hooks/useKeyboardShortcuts";
import { 
  Brain, 
  BarChart3, 
  Dog, 
  Users, 
  Mic,
  University
} from "lucide-react";

export default function Dashboard() {
  const [activeTab, setActiveTab] = useState("research-subjects");

  // Set up keyboard shortcuts for research platform
  useKeyboardShortcuts({
    "ctrl+1": () => setActiveTab("research-subjects"),
    "ctrl+2": () => setActiveTab("behavioral-analysis"),
    "ctrl+3": () => setActiveTab("audio-analysis"),
    "ctrl+4": () => setActiveTab("statistics"),
  });

  // 추가 키보드 접근성
  useEffect(() => {
    const handleKeyPress = (e: KeyboardEvent) => {
      // F1로 도움말 열기
      if (e.key === 'F1') {
        e.preventDefault();
      }

      // ESC로 포커스 해제
      if (e.key === 'Escape') {
        (document.activeElement as HTMLElement)?.blur();
      }
    };

    document.addEventListener('keydown', handleKeyPress);
    return () => document.removeEventListener('keydown', handleKeyPress);
  }, []);

  // Fetch research statistics
  const { data: researchStats } = useQuery({
    queryKey: ["/api/research/statistics"],
  });

  // 기본값 설정
  const stats = researchStats || {
    totalSubjects: 0,
    totalSessions: 0,
    totalAnalyses: 0,
    recentAnalyses: []
  };

  const { data: researchers } = useQuery({
    queryKey: ["/api/research/researchers"],
  });

  return (
    <div className="flex h-screen bg-gray-50">
      {/* 접근성 및 도움말 버튼들 */}
      <div className="fixed bottom-4 left-4 z-50">
        <HelpSystem />
      </div>

      <div className="fixed bottom-4 right-4 z-50">
        <AccessibilityControls />
      </div>

      {/* Main Content */}
      <div className="flex-1 overflow-auto">
        <div className="container mx-auto p-6 space-y-6">
          <div className="flex justify-between items-center">
            <div>
              <h1 className="text-3xl font-bold text-gray-900 flex items-center">
                <Brain className="mr-4 text-blue-600 w-8 h-8" />
                강아지 종합 연구 플랫폼
              </h1>
              <p className="text-gray-600 mt-2">
                AI 기술로 강아지의 행동, 음성, 표정을 종합 분석하는 연구 플랫폼
              </p>
            </div>
          </div>

          {/* Stats Overview */}
          <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
            <StatCard
              title="연구 대상견"
              value={stats.totalSubjects}
              icon={Dog}
              change="+5"
            />
            <StatCard
              title="연구 세션"
              value={stats.totalSessions}
              icon={University}
              change="+12"
            />
            <StatCard
              title="총 분석"
              value={stats.totalAnalyses}
              icon={BarChart3}
              change="+28%"
            />
            <StatCard
              title="연구원"
              value={Array.isArray(researchers) ? researchers.length : 0}
              icon={Users}
              change="+2"
            />
          </div>

          <Tabs value={activeTab} onValueChange={setActiveTab} className="w-full">
            <TabsList className="grid w-full grid-cols-4">
              <TabsTrigger value="research-subjects" className="flex items-center space-x-2">
                <Dog className="w-4 h-4" />
                <span>연구 대상견</span>
              </TabsTrigger>
              <TabsTrigger value="behavioral-analysis" className="flex items-center space-x-2">
                <Brain className="w-4 h-4" />
                <span>행동 분석</span>
              </TabsTrigger>
              <TabsTrigger value="audio-analysis" className="flex items-center space-x-2">
                <Mic className="w-4 h-4" />
                <span>음성 분석</span>
              </TabsTrigger>
              <TabsTrigger value="statistics" className="flex items-center space-x-2">
                <BarChart3 className="w-4 h-4" />
                <span>통계 및 분석</span>
              </TabsTrigger>
            </TabsList>

            <TabsContent value="research-subjects" className="space-y-6">
              <ResearchSubjects />
            </TabsContent>

            <TabsContent value="behavioral-analysis" className="space-y-6">
              <BehavioralAnalysis />
            </TabsContent>

            <TabsContent value="audio-analysis" className="space-y-6">
              <Card className="lg:col-span-2">
                <CardHeader>
                  <CardTitle className="flex items-center space-x-2">
                    <Mic className="w-5 h-5 text-blue-500" />
                    <span>실시간 강아지 음성 분석</span>
                  </CardTitle>
                </CardHeader>
                <CardContent>
                  <AudioRecorder />
                </CardContent>
              </Card>
            </TabsContent>

            <TabsContent value="statistics" className="space-y-6">
              <Card>
                <CardHeader>
                  <CardTitle className="flex items-center space-x-2">
                    <BarChart3 className="w-5 h-5 text-green-500" />
                    <span>연구 통계</span>
                  </CardTitle>
                </CardHeader>
                <CardContent>
                  <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                    <div className="p-4 border rounded-lg">
                      <h3 className="font-semibold text-lg">총 대상견</h3>
                      <p className="text-2xl font-bold text-blue-600">{stats.totalSubjects}</p>
                      <p className="text-sm text-gray-600">등록된 연구 대상견</p>
                    </div>

                    <div className="p-4 border rounded-lg">
                      <h3 className="font-semibold text-lg">연구 세션</h3>
                      <p className="text-2xl font-bold text-green-600">{stats.totalSessions}</p>
                      <p className="text-sm text-gray-600">완료된 연구 세션</p>
                    </div>

                    <div className="p-4 border rounded-lg">
                      <h3 className="font-semibold text-lg">분석 결과</h3>
                      <p className="text-2xl font-bold text-purple-600">{stats.totalAnalyses}</p>
                      <p className="text-sm text-gray-600">행동 및 음성 분석</p>
                    </div>
                  </div>

                  {Array.isArray(stats.recentAnalyses) && stats.recentAnalyses.length > 0 && (
                    <div className="mt-6">
                      <h3 className="font-semibold mb-4">최근 분석 결과</h3>
                      <div className="space-y-2">
                        {stats.recentAnalyses.map((analysis: any, index: number) => (
                          <div key={index} className="flex justify-between items-center p-3 bg-gray-50 rounded">
                            <div>
                              <span className="font-medium">{analysis.behaviorType}</span>
                              <span className="text-sm text-gray-600 ml-2">강도: {analysis.intensity}/10</span>
                            </div>
                            <Badge variant="secondary">
                              신뢰도 {Math.round(analysis.confidence * 100)}%
                            </Badge>
                          </div>
                        ))}
                      </div>
                    </div>
                  )}
                </CardContent>
              </Card>
            </TabsContent>
          </Tabs>
        </div>
      </div>
    </div>
  );
}

