import { useState, useRef, useCallback } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Progress } from "@/components/ui/progress";
import { Button } from "@/components/ui/button";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription, DialogTrigger } from "@/components/ui/dialog";
import { TrendingUp, BarChart, Brain, Target, Play, Pause, Eye, Volume2, Video } from "lucide-react";

export default function PatternAnalysis() {
  const [selectedPattern, setSelectedPattern] = useState<any>(null);
  const [playingAudio, setPlayingAudio] = useState<string | null>(null);
  const [playingVideo, setPlayingVideo] = useState<string | null>(null);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  // 실제 오디오 재생 기능
  const playAudioSample = useCallback(async (audioName: string) => {
    try {
      console.log(`오디오 재생 시작: ${audioName}`);

      // 현재 재생 중인 오디오가 있다면 중지
      if (audioRef.current) {
        audioRef.current.pause();
        audioRef.current.currentTime = 0;
      }

      // 모의 오디오 생성 (실제 구현에서는 서버에서 오디오 파일을 가져옴)
      const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)();
      const oscillator = audioContext.createOscillator();
      const gainNode = audioContext.createGain();

      // 강아지 음성 패턴에 따른 주파수 설정
      let frequency = 220; // 기본 주파수
      if (audioName.includes('식사요구')) {
        frequency = 440; // 높은 톤
      } else if (audioName.includes('산책요구')) {
        frequency = 330; // 중간 톤
      } else if (audioName.includes('놀이')) {
        frequency = 550; // 더 높은 톤
      }

      oscillator.connect(gainNode);
      gainNode.connect(audioContext.destination);

      oscillator.frequency.setValueAtTime(frequency, audioContext.currentTime);
      oscillator.type = 'sawtooth'; // 강아지 울음소리와 유사한 파형

      // 볼륨 조절
      gainNode.gain.setValueAtTime(0, audioContext.currentTime);
      gainNode.gain.linearRampToValueAtTime(0.1, audioContext.currentTime + 0.1);
      gainNode.gain.linearRampToValueAtTime(0.05, audioContext.currentTime + 1);
      gainNode.gain.linearRampToValueAtTime(0, audioContext.currentTime + 2);

      oscillator.start(audioContext.currentTime);
      oscillator.stop(audioContext.currentTime + 2);

      setPlayingAudio(audioName);

      // 재생 완료 후 상태 초기화
      setTimeout(() => {
        setPlayingAudio(null);
        console.log(`오디오 재생 완료: ${audioName}`);
      }, 2000);

    } catch (error: any) {
      console.error('오디오 재생 오류:', error);
      setPlayingAudio(null);

      // 브라우저가 Web Audio API를 지원하지 않는 경우 대체 방법
      alert(`오디오 재생: ${audioName}\n\n실제 시스템에서는 강아지 음성이 재생됩니다.`);
    }
  }, []);

  const stopAudioSample = useCallback(() => {
    console.log('오디오 재생 중지');
    if (audioRef.current) {
      audioRef.current.pause();
      audioRef.current.currentTime = 0;
    }
    setPlayingAudio(null);
  }, []);

  // 비디오 재생 기능 (시뮬레이션)
  const playVideoSample = useCallback(async (videoName: string) => {
    try {
      console.log(`비디오 재생 시작: ${videoName}`);
      setPlayingVideo(videoName);

      // 비디오 재생 시뮬레이션 (3초간)
      setTimeout(() => {
        setPlayingVideo(null);
        console.log(`비디오 재생 완료: ${videoName}`);
      }, 3000);

    } catch (error: any) {
      console.error('비디오 재생 오류:', error);
      setPlayingVideo(null);
    }
  }, []);

  const stopVideoSample = useCallback(() => {
    console.log('비디오 재생 중지');
    setPlayingVideo(null);
  }, []);

  // 모의 패턴 데이터
  const patterns = [
    {
      id: 1,
      pattern: "아침 식사 요구",
      frequency: 85,
      confidence: 94,
      conditions: ["아침", "주인 존재", "부엌 근처"],
      audioSignature: "높은 톤, 반복적 짧은 소리",
      samples: {
        audio: [
          { name: "골든리트리버_식사요구_1.wav", duration: "3.2s", breed: "골든리트리버", date: "2024-01-15" },
          { name: "래브라도_식사요구_2.wav", duration: "2.8s", breed: "래브라도", date: "2024-01-14" },
          { name: "푸들_식사요구_3.wav", duration: "4.1s", breed: "푸들", date: "2024-01-13" }
        ],
        video: [
          { name: "식사요구_행동패턴_1.mp4", duration: "15s", breed: "골든리트리버", description: "그릇 앞에서 짖는 모습" },
          { name: "식사요구_행동패턴_2.mp4", duration: "12s", breed: "래브라도", description: "주인을 따라다니며 요구하는 모습" }
        ]
      }
    },
    {
      id: 2,
      pattern: "산책 요청",
      frequency: 78,
      confidence: 89,
      conditions: ["오후", "맑은 날씨", "목줄 시각"],
      audioSignature: "중간 톤, 길게 늘어지는 소리",
      samples: {
        audio: [
          { name: "시바견_산책요구_1.wav", duration: "5.1s", breed: "시바견", date: "2024-01-15" },
          { name: "치와와_산책요구_2.wav", duration: "3.7s", breed: "치와와", date: "2024-01-14" },
          { name: "말티즈_산책요구_3.wav", duration: "4.3s", breed: "말티즈", date: "2024-01-13" }
        ],
        video: [
          { name: "산책요구_행동패턴_1.mp4", duration: "20s", breed: "시바견", description: "문 앞에서 기다리는 모습" },
          { name: "산책요구_행동패턴_2.mp4", duration: "18s", breed: "치와와", description: "목줄을 물고 오는 모습" }
        ]
      }
    },
    {
      id: 3,
      pattern: "놀이 욕구",
      frequency: 92,
      confidence: 91,
      conditions: ["저녁", "에너지 높음", "장난감 근처"],
      audioSignature: "다양한 톤, 빠른 리듬",
      samples: {
        audio: [
          { name: "믹스견_놀이욕구_1.wav", duration: "2.9s", breed: "믹스견", date: "2024-01-15" },
          { name: "골든리트리버_놀이욕구_2.wav", duration: "3.5s", breed: "골든리트리버", date: "2024-01-14" },
          { name: "푸들_놀이욕구_3.wav", duration: "4.2s", breed: "푸들", date: "2024-01-13" }
        ],
        video: [
          { name: "놀이욕구_행동패턴_1.mp4", duration: "25s", breed: "믹스견", description: "장난감을 물고 흔드는 모습" },
          { name: "놀이욕구_행동패턴_2.mp4", duration: "22s", breed: "골든리트리버", description: "주인에게 장난감을 가져오는 모습" }
        ]
      }
    }
  ];

  const learningProgress = {
    totalSamples: 1247,
    verifiedSamples: 1089,
    accuracyImprovement: 12.3,
    newPatternsFound: 5
  };

  return (
    <div className="space-y-6">
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center space-x-2">
            <Brain className="w-5 h-5 text-purple-500" />
            <span>학습된 행동 패턴</span>
          </CardTitle>
        </CardHeader>
        <CardContent>
          <div className="space-y-4">
            {patterns.map((pattern, index) => (
              <div key={index} className="border rounded-lg p-4 bg-gradient-to-r from-purple-50 to-indigo-50 hover:shadow-md transition-shadow cursor-pointer">
                <div className="flex justify-between items-start mb-3">
                  <h4 className="font-semibold text-purple-800">{pattern.pattern}</h4>
                  <div className="flex space-x-2">
                    <Badge variant="secondary">빈도 {pattern.frequency}%</Badge>
                    <Badge variant="default">신뢰도 {pattern.confidence}%</Badge>
                  </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div>
                    <p className="text-sm font-medium text-gray-600 mb-2">발생 조건:</p>
                    <div className="flex flex-wrap gap-1">
                      {pattern.conditions.map((condition, i) => (
                        <Badge key={i} variant="outline" className="text-xs">
                          {condition}
                        </Badge>
                      ))}
                    </div>
                  </div>

                  <div>
                    <p className="text-sm font-medium text-gray-600 mb-2">음성 특징:</p>
                    <p className="text-sm text-gray-700 italic">{pattern.audioSignature}</p>
                  </div>
                </div>

                <div className="mt-3">
                  <div className="flex justify-between text-sm text-gray-600 mb-1">
                    <span>패턴 인식률</span>
                    <span>{pattern.confidence}%</span>
                  </div>
                  <Progress value={pattern.confidence} className="h-2" />
                </div>

                {/* 샘플 보기 버튼 */}
                <div className="mt-4 flex justify-between items-center">
                  <div className="text-xs text-gray-500">
                    음성 샘플 {pattern.samples.audio.length}개 • 영상 샘플 {pattern.samples.video.length}개
