                                            className={`bg-white h-1 rounded-full transition-all duration-3000 ${
                                              playingVideo === video.name ? 'w-full' : 'w-0'
                                            }`}
                                          />
                                        </div>
                                        <span className={`text-xs transition-colors ${
                                          playingVideo === video.name ? 'text-blue-200 font-medium' : 'text-white'
                                        }`}>
                                          {playingVideo === video.name ? '재생 중...' : video.duration}
                                        </span>
                                      </div>
                                    </div>
                                  </div>
                                </div>
                              </div>
                            ))}
                          </div>
                        </div>

                        {/* 분석 정보 */}
                        <div className="bg-gray-50 rounded-lg p-4">
                          <h4 className="font-semibold text-gray-800 mb-3">🔍 패턴 분석 정보</h4>
                          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                            <div>
                              <div className="text-sm font-medium text-gray-600 mb-2">음성 특징</div>
                              <p className="text-sm text-gray-700">{pattern.audioSignature}</p>
                            </div>
                            <div>
                              <div className="text-sm font-medium text-gray-600 mb-2">발생 조건</div>
                              <div className="flex flex-wrap gap-1">
                                {pattern.conditions.map((condition, i) => (
                                  <Badge key={i} variant="outline" className="text-xs">
                                    {condition}
                                  </Badge>
                                ))}
                              </div>
                            </div>
                          </div>
                        </div>
                      </div>
                    </DialogContent>
                  </Dialog>
                </div>
              </div>
            ))}
          </div>
        </CardContent>
      </Card>

      <Card>
        <CardHeader>
          <CardTitle className="flex items-center space-x-2">
            <TrendingUp className="w-5 h-5 text-green-500" />
            <span>학습 진행 현황</span>
          </CardTitle>
        </CardHeader>
        <CardContent>
          <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
            <div className="text-center p-4 bg-blue-50 rounded-lg">
              <div className="text-2xl font-bold text-blue-600">{learningProgress.totalSamples}</div>
              <div className="text-sm text-blue-800">총 샘플 수</div>
            </div>

            <div className="text-center p-4 bg-green-50 rounded-lg">
              <div className="text-2xl font-bold text-green-600">{learningProgress.verifiedSamples}</div>
              <div className="text-sm text-green-800">검증된 샘플</div>
            </div>

            <div className="text-center p-4 bg-purple-50 rounded-lg">
              <div className="text-2xl font-bold text-purple-600">+{learningProgress.accuracyImprovement}%</div>
              <div className="text-sm text-purple-800">정확도 향상</div>
            </div>

            <div className="text-center p-4 bg-orange-50 rounded-lg">
              <div className="text-2xl font-bold text-orange-600">{learningProgress.newPatternsFound}</div>
              <div className="text-sm text-orange-800">새 패턴 발견</div>
            </div>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

client/src/components/RealTimeMonitor.ts.content:
import { useState, useEffect, useRef } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Progress } from '@/components/ui/progress';

interface StreamLine {
  timestamp: string;
  message: string;
  type: 'info' | 'success' | 'warning' | 'error';
}

interface SystemMetrics {
  cpu: number;
  memory: number;
  gpu: number;
  network: number;
}

export default function RealTimeMonitor() {
  const [dataStream, setDataStream] = useState<StreamLine[]>([
    { timestamp: '14:23:45', message: '🎤 음성 입력 감지...', type: 'info' },
    { timestamp: '14:23:46', message: '📊 주파수 분석 시작', type: 'info' },
    { timestamp: '14:23:47', message: '🧠 AI 모델 처리 중...', type: 'info' },
    { timestamp: '14:23:48', message: '✅ 감정 패턴 인식 완료', type: 'success' },
    { timestamp: '14:23:49', message: '📈 신뢰도 계산: 94.7%', type: 'success' },
  ]);

  const [systemMetrics, setSystemMetrics] = useState<SystemMetrics>({
    cpu: 45,
    memory: 62,
    gpu: 38,
    network: 25
  });

  const [isMonitoring, setIsMonitoring] = useState(true);
  const streamRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!isMonitoring) return;

    const interval = setInterval(() => {
      // 시스템 메트릭 업데이트
      setSystemMetrics({
        cpu: Math.random() * 40 + 30,
        memory: Math.random() * 30 + 50,
        gpu: Math.random() * 50 + 20,
        network: Math.random() * 60 + 10
      });

      // 랜덤 스트림 메시지 추가
      const messages = [
        '🎤 새로운 음성 입력 감지',
        '📊 스펙트럼 분석 완료',
        '🧠 딥러닝 모델 추론 중',
        '✅ 감정 분류 완료',
        '📈 결과 검증 중',
        '💾 데이터 저장 완료'
      ];

      const randomMessage = messages[Math.floor(Math.random() * messages.length)];
      const now = new Date();
      const timestamp = now.toLocaleTimeString('ko-KR', { 
        hour12: false,
        hour: '2-digit',
        minute: '2-digit',
        second: '2-digit'
      });

      const newLine: StreamLine = {
        timestamp,
        message: randomMessage,
        type: Math.random() > 0.8 ? 'warning' : 'info'
      };

      setDataStream(prev => {
        const updated = [...prev, newLine];
        return updated.slice(-20); // 최근 20개만 유지
      });
    }, 3000);

    return () => clearInterval(interval);
  }, [isMonitoring]);

  useEffect(() => {
    // 자동 스크롤
    if (streamRef.current) {
      streamRef.current.scrollTop = streamRef.current.scrollHeight;
    }
  }, [dataStream]);

  const clearStream = () => {
    setDataStream([]);
  };

  const exportStream = () => {
    const data = dataStream.map(line => 
      `[${line.timestamp}] ${line.message}`
    ).join('\n');

    const blob = new Blob([data], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `monitor-log-${new Date().toISOString().slice(0, 10)}.txt`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const getMetricColor = (value: number) => {
    if (value < 30) return 'text-green-600';
    if (value < 70) return 'text-yellow-600';
    return 'text-red-600';
  };

  const getMetricBg = (value: number) => {
    if (value < 30) return 'bg-green-500';
    if (value < 70) return 'bg-yellow-500';
    return 'bg-red-500';
  };

  const getStreamLineColor = (type: string) => {
    switch (type) {
      case 'success': return 'text-green-600';
      case 'warning': return 'text-yellow-600';
      case 'error': return 'text-red-600';
      default: return 'text-blue-600';
    }
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
      {/* 실시간 데이터 스트림 */}
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center space-x-2">
            <span>📡</span>
            <span>실시간 데이터 스트림</span>
          </CardTitle>
          <p className="text-sm text-gray-600">
            음성 분석 과정을 실시간으로 모니터링합니다
          </p>
          <div className="flex items-center space-x-2">
            <Badge variant={isMonitoring ? "default" : "secondary"}>
              {isMonitoring ? '🟢 활성' : '🔴 중지'}
            </Badge>
            <Button 
              variant="outline" 
              size="sm"
              onClick={() => setIsMonitoring(!isMonitoring)}
            >
              {isMonitoring ? '일시정지' : '시작'}
            </Button>
          </div>
        </CardHeader>
        <CardContent>
          <div 
            ref={streamRef}
            className="data-stream"
          >
            {dataStream.map((line, index) => (
              <div 
                key={index} 
                className={`stream-line ${getStreamLineColor(line.type)}`}
                style={{ animationDelay: `${index * 0.1}s` }}
              >
                [{line.timestamp}] {line.message}
              </div>
            ))}
            {dataStream.length === 0 && (
              <div className="text-gray-500 text-center mt-20">
                스트림이 비어있습니다
              </div>
            )}
          </div>

          <div className="flex space-x-2 mt-4">
            <Button onClick={clearStream} variant="outline" size="sm">
              🧹 스트림 지우기
            </Button>
            <Button onClick={exportStream} variant="outline" size="sm">
              💾 데이터 내보내기
            </Button>
          </div>
        </CardContent>
      </Card>

      {/* 시스템 성능 모니터 */}
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center space-x-2">
            <span>⚙️</span>
            <span>시스템 성능 모니터</span>
          </CardTitle>
          <p className="text-sm text-gray-600">
            AI 엔진의 실시간 성능을 추적합니다
          </p>
        </CardHeader>
        <CardContent className="space-y-6">
          {/* CPU 사용률 */}
          <div className="bg-gray-50 p-4 rounded-lg">
            <div className="flex justify-between items-center mb-2">
              <span className="font-medium">CPU 사용률</span>
              <span className={`font-bold ${getMetricColor(systemMetrics.cpu)}`}>
                {systemMetrics.cpu.toFixed(1)}%
              </span>
            </div>
            <div className="performance-meter">
              <div 
                className="performance-fill cpu"
                style={{ width: `${systemMetrics.cpu}%` }}
              />
            </div>
          </div>

          {/* 메모리 사용률 */}
          <div className="bg-gray-50 p-4 rounded-lg">
            <div className="flex justify-between items-center mb-2">
              <span className="font-medium">메모리 사용률</span>
              <span className={`font-bold ${getMetricColor(systemMetrics.memory)}`}>
                {systemMetrics.memory.toFixed(1)}%
              </span>
            </div>
            <div className="performance-meter">
              <div 
                className="performance-fill memory"
                style={{ width: `${systemMetrics.memory}%` }}
              />
            </div>
          </div>

          {/* GPU 사용률 */}
          <div className="bg-gray-50 p-4 rounded-lg">
            <div className="flex justify-between items-center mb-2">
              <span className="font-medium">GPU 사용률</span>
              <span className={`font-bold ${getMetricColor(systemMetrics.gpu)}`}>
                {systemMetrics.gpu.toFixed(1)}%
              </span>
            </div>
            <div className="performance-meter">
              <div 
                className="performance-fill gpu"
                style={{ width: `${systemMetrics.gpu}%` }}
              />
            </div>
          </div>

          {/* 네트워크 사용률 */}
          <div className="bg-gray-50 p-4 rounded-lg">
            <div className="flex justify-between items-center mb-2">
              <span className="font-medium">네트워크 사용률</span>
              <span className={`font-bold ${getMetricColor(systemMetrics.network)}`}>
                {systemMetrics.network.toFixed(1)}%
              </span>
            </div>
            <div className="performance-meter">
              <div 
                className="performance-fill network"
                style={{ width: `${systemMetrics.network}%` }}
              />
            </div>
          </div>

          {/* 시스템 상태 요약 */}
          <div className="bg-gray-50 rounded-lg p-4">
            <h4 className="font-semibold mb-3">시스템 상태 요약</h4>
            <div className="grid grid-cols-2 gap-4 text-sm">
              <div>
                <span className="text-gray-600">온라인 시간:</span>
                <div className="font-medium">2시간 34분</div>
              </div>
              <div>
                <span className="text-gray-600">처리된 요청:</span>
                <div className="font-medium">1,247개</div>
              </div>
              <div>
                <span className="text-gray-600">평균 응답시간:</span>
                <div className="font-medium">1.2초</div>
              </div>
              <div>
                <span className="text-gray-600">오류율:</span>
                <div className="font-medium text-green-600">0.1%</div>
              </div>
            </div>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

client/src/components/VisualInsights.tsx.content:
import { useState, useEffect } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';

interface EmotionHeatmapData {
  emotion: string;
  intensity: 'low' | 'medium' | 'high' | 'very-high';
  emoji: string;
}

interface AnalysisMetrics {
  voiceQuality: number;
  aiConfidence: number;
  processingSpeed: number;
  accuracy: number;
}

export default function VisualInsights() {
  const [isRotating, setIsRotating] = useState(false);
  const [emotionData, setEmotionData] = useState<EmotionHeatmapData[]>([
    { emotion: '기쁨', intensity: 'high', emoji: '😊' },
    { emotion: '불안', intensity: 'medium', emoji: '😰' },
    { emotion: '경계', intensity: 'very-high', emoji: '🚨' },
    { emotion: '요구', intensity: 'high', emoji: '🙏' },
    { emotion: '좌절', intensity: 'low', emoji: '😤' },
    { emotion: '놀이', intensity: 'medium', emoji: '🎾' },
  ]);

  const [metrics, setMetrics] = useState<AnalysisMetrics>({
    voiceQuality: 96,
    aiConfidence: 94.7,
    processingSpeed: 1.2,
    accuracy: 97.3
  });

  const getIntensityColor = (intensity: string) => {
    switch (intensity) {
      case 'low': return 'rgba(52, 152, 219, 0.2)';
      case 'medium': return 'rgba(241, 196, 15, 0.4)';
      case 'high': return 'rgba(231, 76, 60, 0.6)';
      case 'very-high': return 'rgba(192, 57, 43, 0.8)';
      default: return 'rgba(52, 152, 219, 0.2)';
    }
  };

  const toggle3DRotation = () => {
    setIsRotating(!isRotating);
  };

  return (
    <div className="space-y-6">
      {/* 감정 히트맵 */}
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center space-x-2">
            <span>🌡️</span>
            <span>감정 강도 히트맵</span>
          </CardTitle>
          <p className="text-sm text-gray-600">
            최근 분석된 음성의 감정별 강도를 시각화합니다
          </p>
        </CardHeader>
        <CardContent>
          <div className="heatmap-grid">
            {emotionData.map((item, index) => (
              <div
                key={index}
                className={`heatmap-cell ${item.intensity}`}
                style={{ backgroundColor: getIntensityColor(item.intensity) }}
              >
                <div className="text-center">
                  <div className="text-3xl mb-1">{item.emoji}</div>
                  <div className="text-sm font-medium">{item.emotion}</div>
                </div>
              </div>
            ))}
          </div>

          <div className="flex justify-between items-center text-xs text-gray-500">
            <span>낮음</span>
            <div className="flex space-x-1">
              {['low', 'medium', 'high', 'very-high'].map((level) => (
                <div
                  key={level}
                  className="w-5 h-2 rounded"
                  style={{ backgroundColor: getIntensityColor(level) }}
                />
              ))}
            </div>
            <span>높음</span>
          </div>
        </CardContent>
      </Card>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* 실시간 스펙트로그램 */}
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center space-x-2">
              <span>🌈</span>
              <span>실시간 스펙트로그램</span>
            </CardTitle>
            <p className="text-sm text-gray-600">
              음성의 주파수 성분을 실시간으로 분석합니다
            </p>
          </CardHeader>
          <CardContent>
            <div className="spectrogram-container">
              {Array.from({ length: 20 }).map((_, i) => (
                <div
                  key={i}
                  className="spectrogram-bar"
                  style={{
                    height: `${Math.random() * 80 + 20}%`,
                    animationDelay: `${i * 0.1}s`
                  }}
                />
              ))}
            </div>
            <div className="flex justify-between mt-2 text-xs text-gray-500">
              <span>저주파</span>
              <span>중주파</span>
              <span>고주파</span>
            </div>
          </CardContent>
        </Card>

        {/* 3D 음성 분석 */}
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center space-x-2">
              <span>📈</span>
              <span>3D 음성 패턴 분석</span>
            </CardTitle>
            <p className="text-sm text-gray-600">
              시간-주파수-강도의 3차원 분석
            </p>
          </CardHeader>
          <CardContent>
            <div className="chart-3d-container">
              {[60, 80, 45, 90, 70, 55].map((height, i) => (
                <div
                  key={i}
                  className={`chart-3d-bar ${isRotating ? 'rotating' : ''}`}
                  style={{
                    height: `${height}%`,
                    animationDelay: `${i * 0.1}s`
                  }}
                />
              ))}
            </div>
            <div className="text-center mt-4">
              <Button onClick={toggle3DRotation} variant="outline" size="sm">
                🔄 회전 토글
              </Button>
            </div>
          </CardContent>
        </Card>
      </div>

      {/* 종합 분석 대시보드 */}
      <Card className="bg-gradient-to-r from-indigo-500 to-purple-600 text-white">
        <CardHeader>
          <CardTitle className="flex items-center space-x-2">
            <span>🎯</span>
            <span>종합 분석 대시보드</span>
          </CardTitle>
        </CardHeader>
        <CardContent>
          <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
            <div className="bg-white/10 backdrop-blur rounded-lg p-4 text-center">
              <div className="text-3xl mb-2">🎵</div>
              <div className="text-lg font-semibold mb-1">음성 품질</div>
              <div className="text-2xl font-bold text-yellow-300">{metrics.voiceQuality}%</div>
            </div>
            <div className="bg-white/10 backdrop-blur rounded-lg p-4 text-center">
              <div className="text-3xl mb-2">🧠</div>
              <div className="text-lg font-semibold mb-1">AI 신뢰도</div>
              <div className="text-2xl font-bold text-cyan-300">{metrics.aiConfidence}%</div>
            </div>
            <div className="bg-white/10 backdrop-blur rounded-lg p-4 text-center">
              <div className="text-3xl mb-2">⚡</div>
              <div className="text-lg font-semibold mb-1">처리 속도</div>
              <div className="text-2xl font-bold text-pink-300">{metrics.processingSpeed}초</div>
            </div>
            <div className="bg-white/10 backdrop-blur rounded-lg p-4 text-center">
              <div className="text-3xl mb-2">🎯</div>
              <div className="text-lg font-semibold mb-1">정확도</div>
              <div className="text-2xl font-bold text-purple-300">{metrics.accuracy}%</div>
            </div>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

